input.content:
/**
 * Access Codes Collection
 *
 * @fileType collection-config
 * @domain access-control
 * @pattern access-code-gate
 * @ai-summary Collection for managing school access codes that unlock lessons
 */

import type { CollectionConfig } from 'payload'

import { adminOnly } from '../access/adminOnly'
import { createdByField } from '../fields/createdBy'
import { tenantField } from '../fields/tenant'

export const AccessCodes: CollectionConfig = {
  slug: 'access-codes',
  admin: {
    useAsTitle: 'code',
    defaultColumns: ['code', 'label', 'lesson', 'currentRedemptions', 'maxRedemptions', 'isActive', 'expiresAt'],
    group: 'Access Control',
  },
  access: {
    create: adminOnly,
    delete: adminOnly,
    read: adminOnly,
    update: adminOnly,
  },
  fields: [
    {
      name: 'code',
      type: 'text',
      required: true,
      unique: true,
      index: true,
      admin: {
        description: 'The code students enter to unlock content (e.g., MACCABI-2024-FREE)',
      },
    },
    {
      name: 'label',
      type: 'text',
      admin: {
        description: 'Admin-friendly name/description for this code',
      },
    },
    {
      name: 'lesson',
      type: 'relationship',
      relationTo: 'lessons',
      required: true,
      admin: {
        description: 'The lesson this code unlocks',
      },
    },
    {
      name: 'maxRedemptions',
      type: 'number',
      min: 1,
      admin: {
        description: 'Maximum number of times this code can be redeemed (leave empty for unlimited)',
      },
    },
    {
      name: 'currentRedemptions',
      type: 'number',
      required: true,
      defaultValue: 0,
      admin: {
        readOnly: true,
        description: 'Number of times this code has been redeemed',
      },
    },
    {
      name: 'isActive',
      type: 'checkbox',
      required: true,
      defaultValue: true,
      admin: {
        description: 'Whether this code is currently valid',
      },
    },
    {
      name: 'expiresAt',
      type: 'date',
      admin: {
        description: 'Expiration date (leave empty for no expiration)',
      },
    },
    // Created By
    createdByField,
    // Tenant
    tenantField,
  ],
  timestamps: true,
}

