  const handleAuthChange = useCallback(() => {
    clearGateTimer(courseSlug)
    setElapsedMs(0)
  }, [courseSlug])

  useEffect(() => {
    window.addEventListener('auth:changed', handleAuthChange)
    return () => window.removeEventListener('auth:changed', handleAuthChange)
  }, [handleAuthChange])

