      const updateElapsed = () => {
        const stored = getGateTimerStart(courseSlug)
        if (stored) {
          setElapsedMs(Date.now() - stored)
        }
      }
      updateElapsed()
      intervalRef.current = setInterval(updateElapsed, 1000)
    }
  }, [showWarningModal, courseSlug])

  return {
    showMandatoryModal,
    showGatedModal,
    showWarningModal,
    showAccessCodeModal,
    hasCodeAccess,
    isCheckingAccess,
    warningSecondsLeft,
    dismissWarning,
    onCodeRedeemed,
    user,
    isAuthLoading,
  }
}

